PRAGMA foreign_keys=OFF;
CREATE TABLE foods (
  id              INTEGER PRIMARY KEY AUTOINCREMENT,
  description     TEXT    NOT NULL,
  serving_size    TEXT    NOT NULL,
  fat_g           REAL,
  calories        INTEGER,
  carbohydrate_g  REAL,
  protein_g       REAL,
  cholesterol_mg  REAL,
  weight_g        REAL,
  saturated_fat_g REAL,

  calorie_density REAL GENERATED ALWAYS AS (
    CASE 
      WHEN weight_g > 0 AND calories IS NOT NULL
      THEN calories * 1.0 / weight_g
      ELSE 0
    END
  ) VIRTUAL
);
DELETE FROM sqlite_sequence;
